import{getProductById as t,formatPrice as a}from"../data/products.js";import{addItem as r}from"../services/cart.js";export function renderProduct(e,c){var i=t(c.id);if(i){var d=Object.keys(i.specs).map(function(t){return'<tr><th scope="row">'+t.charAt(0).toUpperCase()+t.slice(1)+"</th><td>"+i.specs[t]+"</td></tr>"}).join("");e.innerHTML='<div class="container product-detail"><nav class="breadcrumb" aria-label="Breadcrumb"><a href="/catalog" data-route>Catalog</a> / <span aria-current="page">'+i.name+'</span></nav><article class="product-detail__grid"><figure class="product-detail__media"><img src="'+i.image+'" alt="'+i.name+'" width="480" height="360" loading="eager"></figure><div class="product-detail__info"><h1>'+i.name+'</h1><p class="catalog-card__price">'+a(i.price)+'</p><p class="product-detail__rating">Rating: '+i.rating+" / 5</p><p>"+i.description+'</p><table class="product-specs" aria-label="Product specifications"><tbody>'+d+'</tbody></table><button type="button" id="product-add-btn" class="btn btn--primary"'+(i.inStock?"":" disabled")+">"+(i.inStock?"Add to Cart":"Out of Stock")+"</button></div></article></div>";var o=e.querySelector("#product-add-btn");o&&o.addEventListener("click",function(){r(i.id),o.textContent="Added to Cart!"})}else e.innerHTML='<div class="container"><p class="weather-status weather-status--error" role="alert">Product not found.</p><a href="/catalog" class="btn btn--primary" data-route>Back to catalog</a></div>'}